INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('2066e3e8-629b-5c4e-a2a1-9a6cf7a2961d', 'math-5eme', 'المحيط والمساحة', 'حساب محيط المربّع والمستطيل والمثلّث، حساب مساحة المربّع والمستطيل، وحدات المساحة (cm²، m²، km²) وتحويلاتها البسيطة، والتمييز بين المحيط والمساحة', '# ⚔️ المحيط والمساحة — حارسا الأشكال

> 💡 «المحيط يَحرُس الحدود، والمساحة تَحكُم الداخل: بطلٌ واحدٌ يُتقن الاثنين معًا.»

أهلًا بك أيّها البطل في بوّابةٍ جديدة من مغامرة السنة الخامسة! هنا تلتقي **قوّتان** للأشكال المستوية: **المحيط** الذي يقيس الطريق _حول_ الشكل، و**المساحة** التي تقيس المكان الذي _يملؤه_ الشكل. كثيرٌ من المغامرين يخلطون بينهما — أمّا أنت فستُميّزهما بوضوح وتحسبهما بثقة.

## 🧭 المحيط: الطريق حول الشكل

**محيط** مضلّعٍ هو **مجموع أطوال أضلاعه** كلّها (طول الخطّ المغلق المحيط بالشكل). نقيسه بوحدات الطول: **cm، m، km…**

### 🟦 محيط المربّع

أضلاع المربّع الأربعة **متساوية**، فمحيطه يساوي أربعة أمثال الضلع:

$$محيط المربّع = 4 × الضلع$$

<svg viewBox="0 0 100 100"><rect x="25" y="25" width="50" height="50" fill="none" stroke="currentColor" stroke-width="2.5"/><text x="44" y="20" font-size="10" fill="currentColor">5 cm</text></svg>

- _مثال:_ مربّعٌ ضلعه 5 cm: المحيط = 4 × 5 = **20 cm**.

### 🟩 محيط المستطيل

للمستطيل ضلعان بالطول وضلعان بالعرض، فمحيطه يساوي ضِعفَ مجموع الطول والعرض:

$$محيط المستطيل = 2 × (الطول + العرض)$$

<svg viewBox="0 0 100 100"><rect x="15" y="32" width="70" height="36" fill="none" stroke="currentColor" stroke-width="2.5"/><text x="40" y="27" font-size="10" fill="currentColor">8 cm</text><text x="2" y="53" font-size="10" fill="currentColor">3</text></svg>

- _مثال:_ مستطيلٌ طوله 8 cm وعرضه 3 cm: المحيط = 2 × (8 + 3) = 2 × 11 = **22 cm**.

### 🔺 محيط المثلّث

محيط المثلّث هو **مجموع أطوال أضلاعه الثلاثة**:

$$محيط المثلّث = a + b + c$$

- _مثال:_ مثلّثٌ أضلاعه 4 cm و 5 cm و 6 cm: المحيط = 4 + 5 + 6 = **15 cm**.

## 🟫 المساحة: المكان الذي يملؤه الشكل

**مساحة** شكلٍ هي **مقدار السطح الذي يشغله** (عدد المربّعات الواحدة التي تملؤه). نقيسها بوحدات المساحة: **cm²، m²، km²…**

> 🗡️ تخيّل أنّك تبلّط أرضًا بمربّعاتٍ صغيرة طول ضلعها 1 cm؛ عددُ المربّعات اللازمة هو المساحة بالـ cm².

### 🟦 مساحة المربّع

نضرب الضلع في نفسه:

$$مساحة المربّع = الضلع × الضلع$$

- _مثال:_ مربّعٌ ضلعه 5 cm: المساحة = 5 × 5 = **25 cm²**.

### 🟩 مساحة المستطيل

نضرب الطول في العرض:

$$مساحة المستطيل = الطول × العرض$$

<svg viewBox="0 0 100 100"><rect x="15" y="30" width="60" height="40" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="35" y1="30" x2="35" y2="70" stroke="currentColor" stroke-width="0.7"/><line x1="55" y1="30" x2="55" y2="70" stroke="currentColor" stroke-width="0.7"/><line x1="15" y1="50" x2="75" y2="50" stroke="currentColor" stroke-width="0.7"/><text x="33" y="25" font-size="10" fill="currentColor">6 cm</text><text x="2" y="53" font-size="10" fill="currentColor">4</text></svg>

- _مثال:_ مستطيلٌ طوله 6 cm وعرضه 4 cm: المساحة = 6 × 4 = **24 cm²** (يَتكوّن من 6 × 4 = 24 مربّعًا صغيرًا).

## 📏 وحدات المساحة وتحويلاتها

كلّ وحدة مساحةٍ هي مربّعٌ ضلعه وحدة الطول الموافقة:

| الوحدة | معناها           |
| ------ | ---------------- |
| 1 cm²  | مربّعٌ ضلعه 1 cm |
| 1 m²   | مربّعٌ ضلعه 1 m  |
| 1 km²  | مربّعٌ ضلعه 1 km |

التحويل بين الوحدات يقوم على ضرب أطوال الأضلاع:

- 1 m = 100 cm، إذن **1 m² = 100 × 100 = 10 000 cm²**.
- 1 km = 1 000 m، إذن **1 km² = 1 000 × 1 000 = 1 000 000 m²**.

- _مثال:_ مساحةٌ قدرها 3 m² = 3 × 10 000 = **30 000 cm²**.

> ⚠️ انتبه: عند تحويل المساحة نضرب في **العدد مرّتين** (مربّعًا)، لا مرّةً واحدة كما في الطول. فـ 1 m² ليست 100 cm² بل 10 000 cm².

## 🛡️ المحيط أم المساحة؟ لا تخلط!

هذان مفهومان مختلفان تمامًا، لكلٍّ منهما وحدتُه:

| المفهوم | ما يقيسه         | وحدته       |
| ------- | ---------------- | ----------- |
| المحيط  | الطريق حول الشكل | cm، m (طول) |
| المساحة | السطح داخل الشكل | cm²، m²     |

- _مثالٌ كاشف:_ مستطيلٌ طوله 6 cm وعرضه 3 cm:
  - **المحيط** = 2 × (6 + 3) = 18 cm (وحدةُ طول).
  - **المساحة** = 6 × 3 = 18 cm² (وحدةُ مساحة).
  - العددان متساويان هنا بالصدفة، لكنّ المعنى والوحدة مختلفان!

> ⚠️ الفخّ الشائع: استعمال **الجمع** لإيجاد المساحة، أو **الضرب** لإيجاد المحيط. تذكّر: المحيط جمعٌ (طول × مرّاتٍ)، والمساحة ضربٌ (طول × طول)، ونتيجتُها بوحدةٍ مربّعة.

> 🏆 صرت الآن تَحرُس حدود الأشكال بالمحيط، وتَحكُم داخلها بالمساحة، وتُحوّل بين وحدات المساحة بثقة. أتقنتَ بوّابةً من أهمّ بوّابات الهندسة! استعدّ للبوّابة الموالية.', '# 📜 ملخّص: المحيط والمساحة

- **المحيط:** مجموع أطوال أضلاع الشكل (الطريق حوله)، يُقاس بوحدات الطول cm، m.
- **محيط المربّع** = 4 × الضلع، مثل ضلع 5 cm ⟸ المحيط 20 cm.
- **محيط المستطيل** = 2 × (الطول + العرض)، مثل 8 cm و 3 cm ⟸ المحيط 22 cm.
- **محيط المثلّث** = مجموع أضلاعه الثلاثة، مثل 4 + 5 + 6 = 15 cm.
- **المساحة:** مقدار السطح الذي يشغله الشكل، يُقاس بوحدات المساحة cm²، m²، km².
- **مساحة المربّع** = الضلع × الضلع، مثل ضلع 5 cm ⟸ المساحة 25 cm².
- **مساحة المستطيل** = الطول × العرض، مثل 6 cm و 4 cm ⟸ المساحة 24 cm².
- **وحدات المساحة:** 1 m² = 10 000 cm²، و 1 km² = 1 000 000 m² (نضرب طول التحويل في نفسه).
- **المحيط ≠ المساحة:** المحيط طولٌ (جمع، وحدتُه cm)، والمساحة سطحٌ (ضرب، وحدتُها cm²)؛ لا تخلط بينهما.', 9)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('4462f581-db3b-5244-86df-6c9a87ddcc9f', 'math-5eme', 'التناسب والنسبة المئوية', 'وضعيّات التناسب وجدول التناسب، معامل التناسب والمرور بالوحدة، التعرّف على وضعيّة متناسبة، النسبة المئوية ومعنى %، حساب نسبة مئوية بسيطة من كمّيّة، وحلّ مسائل بسيطة في الأثمان والتخفيضات والوصفات', '# ⚔️ التناسب والنسبة المئوية — بوّابة التوازن السحريّ

> 💡 «من يَفهم التناسب يَقرأ علاقةً خفيّةً بين عددين، فيَحسب ثمنَ أيّ كمّيّةٍ في لمح البصر.»

أهلًا بك أيّها البطل في بوّابةٍ جديدة من مغامرة السنة الخامسة. هنا نتعلّم سلاحًا قويًّا يُستعمل كلّ يوم: عند شراء الفواكه، وحساب التخفيضات في المتجر، وتحضير الوصفات. هذا السلاح اسمه **التناسب**، ومنه تنبثق **النسبة المئوية**.

## 🏰 ما هي وضعيّة التناسب؟

نقول إنّ كمّيّتين **متناسبتان** إذا كانت إحداهما تُضرب دائمًا في **العدد نفسه** لنحصل على الأخرى.

_مثال:_ ثمن الأقلام: القلم الواحد بـ 2 دينار.

| عدد الأقلام | 1   | 2   | 3   | 5   |
| ----------- | --- | --- | --- | --- |
| الثمن (د)   | 2   | 4   | 6   | 10  |

نلاحظ أنّ كلّ عددٍ في السطر الأوّل نضربه في **2** لنحصل على الثمن. هذا العدد الثابت (هنا 2) اسمه **معامل التناسب**.

> 🗡️ القاعدة الذهبيّة: في التناسب، إذا تضاعف أحد العددين تضاعف الآخر؛ وإذا صار ثلاثة أمثاله صار الآخر كذلك. علاقةٌ بالضرب لا بالجمع.

## 🧮 كيف نتعرّف على وضعيّة متناسبة؟

نضع الأعداد في **جدولٍ**، ثمّ نتحقّق: هل ننتقل من السطر الأوّل إلى الثاني بضربٍ في **العدد نفسه** في كلّ الأعمدة؟

- إن كان معامل التناسب **واحدًا في كلّ الأعمدة** ⟸ الوضعيّة **متناسبة**.
- إن اختلف من عمودٍ إلى آخر ⟸ الوضعيّة **غير متناسبة**.

_مثال غير متناسب:_ سنُّ طفلٍ وطولُه. عند سنّ 2 يكون طوله 85 سم، وعند سنّ 4 يكون 100 سم؛ لو كان متناسبًا لصار الطول 170 سم، وهذا غير صحيح. إذن السنّ والطول **غير متناسبين**.

## 🔮 معامل التناسب والمرور بالوحدة

لإكمال جدول تناسبٍ نستعمل طريقتين:

**1) معامل التناسب:** نجد العدد الثابت ثمّ نضرب به. إذا كان القلم بـ 2 دينار، فثمنُ 7 أقلام = 7 × 2 = 14 دينارًا.

**2) المرور بالوحدة:** نحسب أوّلًا ثمن **الوحدة الواحدة**، ثمّ نضرب في العدد المطلوب.

_مثال:_ 4 خبزاتٍ بـ 2 دينار. كم ثمن 10 خبزات؟ نمرّ بالوحدة: ثمن الخبزة الواحدة = 2 ÷ 4 = 0,5 دينار، فثمن 10 خبزات = 10 × 0,5 = 5 دينار.

## ⚡ ما هي النسبة المئوية؟

**النسبة المئوية** هي طريقةٌ خاصّة للتعبير عن جزءٍ من كلٍّ، أساسُها العدد **100**. الرمز **%** يعني «من كلّ مئة».

- 25 % تعني **25 من كلّ 100**، أي الكسر 25/100.
- 50 % تعني النصف، لأنّ 50/100 = 1/2.
- 100 % تعني الكلّ كاملًا.

| النسبة المئوية | كسرها  | معناها  |
| -------------- | ------ | ------- |
| 10 %           | 10/100 | العُشر  |
| 20 %           | 20/100 | الخُمس  |
| 25 %           | 25/100 | الرُّبع |
| 50 %           | 50/100 | النصف   |

## 🛡️ كيف نحسب نسبةً مئويةً من كمّيّة؟

لحساب «n % من كمّيّة» نضرب الكمّيّة في n ثمّ نقسم على 100:

$$n \% \text{ من العدد} = \text{العدد} × n ÷ 100$$

- _مثال:_ احسب 25 % من 80. ⟸ 80 × 25 ÷ 100 = 2000 ÷ 100 = **20**.
- _مثال:_ احسب 10 % من 50. ⟸ 50 × 10 ÷ 100 = 500 ÷ 100 = **5**.
- _مثال:_ احسب 50 % من 60. ⟸ 60 × 50 ÷ 100 = 3000 ÷ 100 = **30** (وهو النصف، فالحساب يوافق المعنى).

> 🗡️ حيلة سريعة: 10 % يعني القسمة على 10، و 50 % يعني النصف، و 25 % يعني الرُّبع (القسمة على 4). 20 % من 50 = 50 ÷ 5 = 10.

## 📐 مسائل التخفيض والأثمان

في المتاجر يُكتب التخفيض بالنسبة المئوية. لحساب الثمن بعد التخفيض:

1. نحسب **مقدار التخفيض** (نسبة مئوية من الثمن).
2. نطرحه من الثمن الأصليّ.

_مثال:_ قميصٌ ثمنه 40 دينارًا، عليه تخفيض 25 %.

- مقدار التخفيض = 40 × 25 ÷ 100 = 10 دينار.
- الثمن بعد التخفيض = 40 − 10 = **30 دينارًا**.

> ⚠️ الفخّ الشائع: ظنّ أنّ 20 % من 50 يساوي 20؛ والصواب أنّ النسبة تُحسب من الكمّيّة: 50 × 20 ÷ 100 = 10. النسبة المئوية **ليست** عددًا ثابتًا، بل تعتمد على الكمّيّة التي نأخذها منها.

> 🏆 لقد عبرت بوّابة التوازن السحريّ! صرت تتعرّف على وضعيّات التناسب، وتُكمل جداولها بمعامل التناسب أو المرور بالوحدة، وتَحسب النسب المئويّة، وتحلّ مسائل الأثمان والتخفيضات. استعدّ للبوّابة الموالية!', '# 📜 ملخّص: التناسب والنسبة المئوية

- **وضعيّة متناسبة:** كمّيّتان نمرّ من إحداهما إلى الأخرى بالضرب في **العدد نفسه** دائمًا (علاقة ضربٍ لا جمع).
- **معامل التناسب:** العدد الثابت الذي نضرب به؛ مثل القلم بـ 2 د، فثمن 7 أقلام = 7 × 2 = 14 د.
- **المرور بالوحدة:** نحسب ثمن الوحدة الواحدة ثمّ نضرب؛ مثل 4 خبزاتٍ بـ 2 د ⟸ الخبزة 0,5 د، فـ 10 خبزات = 5 د.
- **التعرّف على التناسب:** الوضعيّة متناسبة إذا كان معامل التناسب نفسه في كلّ الأعمدة، وإلّا فهي غير متناسبة.
- **النسبة المئوية %:** جزءٌ من كلٍّ أساسُه 100؛ 25 % = 25/100، و 50 % = النصف، و 10 % = العُشر، و 20 % = الخُمس.
- **حساب n % من كمّيّة:** الكمّيّة × n ÷ 100؛ مثل 25 % من 80 = 80 × 25 ÷ 100 = 20.
- **التخفيض:** مقدار التخفيض = نسبة مئوية من الثمن، ثمّ الثمن الجديد = الثمن − مقدار التخفيض؛ مثل 25 % من 40 د = 10 د، فالثمن 30 د.
- **انتبه:** النسبة تُحسب من الكمّيّة؛ 20 % من 50 = 10 وليست 20.', 10)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('9cee0386-651b-5a63-b23c-07ed1c8aa60d', 'math-5eme', 'الهندسة', 'المستقيمات المتوازية والمتعامدة ورموزها (∥ و ⊥)، أنواع الزوايا (قائمة، حادّة، منفرجة، مستقيمة)، أنواع المثلّثات (قائم، متساوي الساقين، متساوي الأضلاع، أيّ مثلّث)، الرباعيّات وخصائصها (المربّع، المستطيل، المعيّن، متوازي الأضلاع)، والدائرة (المركز، الشعاع، القطر؛ القطر = 2 × الشعاع)', '# ⚔️ الهندسة — مملكة الخطوط والأشكال

> 💡 «الهندسة لغةُ الأشكال: خطوطٌ تتوازى أو تتعامد، زوايا تنفتح، ومثلّثاتٌ ودوائر تُبنى منها. من يُتقنها يقرأ كلّ شكلٍ من حوله.»

أهلًا بك أيّها البطل في بوّابة **الهندسة**. تعرف من قبلُ المستقيمات والزوايا والمضلّعات؛ اليوم نُتقن **رموز التوازي والتعامد**، ونميّز **أنواع المثلّثات** و**الرباعيّات** وخصائصها، ونكتشف عالَم **الدائرة**.

## 📍 المستقيمات: التوازي والتعامد

- **مستقيمان متوازيان (∥):** لا يتقاطعان أبدًا مهما امتدّا، ويحافظان على نفس المسافة بينهما. نكتب (D1) ∥ (D2).
- **مستقيمان متعامدان (⊥):** يتقاطعان مكوّنَين **زاويةً قائمة** (90 درجة)، ونضع علامة الزاوية القائمة (مربّعًا صغيرًا) عند نقطة التقاطع. نكتب (D1) ⊥ (D2).

<svg viewBox="0 0 100 100"><line x1="50" y1="10" x2="50" y2="90" stroke="currentColor" stroke-width="3"/><line x1="10" y1="50" x2="90" y2="50" stroke="currentColor" stroke-width="3"/><polyline points="50,62 62,62 62,50" fill="none" stroke="currentColor" stroke-width="2"/></svg>

> 🗡️ نتحقّق من التعامد بـ**الكوس** (المثلّث القائم)، ومن التوازي بـ**المسطرة والكوس** (تساوي المسافة في عدّة مواضع).

## 📐 أنواع الزوايا

عند التقاء نصفَي مستقيمٍ في نقطة (الرأس) تتكوّن **زاوية**، نقيسها بمقدار انفتاحها بالدرجات:

| النوع   | الانفتاح          | المقارنة بالقائمة   |
| ------- | ----------------- | ------------------- |
| حادّة   | أقلّ من 90 درجة   | أصغر من القائمة     |
| قائمة   | 90 درجة           | تساوي القائمة       |
| منفرجة  | بين 90 و 180 درجة | أكبر من القائمة     |
| مستقيمة | 180 درجة          | الضلعان على استقامة |

<svg viewBox="0 0 100 100"><line x1="20" y1="80" x2="90" y2="80" stroke="currentColor" stroke-width="3"/><line x1="20" y1="80" x2="20" y2="15" stroke="currentColor" stroke-width="3"/><polyline points="20,68 32,68 32,80" fill="none" stroke="currentColor" stroke-width="2"/><circle cx="20" cy="80" r="2.5" fill="currentColor"/></svg>

> ⚠️ الفخّ الشائع: الخلط بين الحادّة والمنفرجة؛ تذكّر أنّ **الحادّة ضيّقة** (أصغر من الرّكن) و**المنفرجة واسعة** (أكبر من الرّكن).

## 🔺 المثلّثات وأنواعها

**المثلّث** مضلّعٌ له 3 أضلاع و3 رؤوس و3 زوايا. نميّز أنواعه حسب أضلاعه وزواياه:

- **المثلّث القائم:** فيه **زاويةٌ قائمة** واحدة.
- **المثلّث متساوي الساقين:** له **ضلعان متساويان** (الساقان).
- **المثلّث متساوي الأضلاع:** أضلاعه **الثلاثة متساوية** (وزواياه الثلاث متساوية أيضًا).
- **المثلّث أيّ (مختلف الأضلاع):** أضلاعه الثلاثة مختلفة ولا زاوية قائمة فيه.

<svg viewBox="0 0 100 100"><polygon points="50,15 15,85 85,85" fill="none" stroke="currentColor" stroke-width="3"/></svg>

> 🗡️ المثلّث القائم نُميّزه بعلامة الزاوية القائمة عند أحد رؤوسه:

<svg viewBox="0 0 100 100"><polygon points="20,20 20,85 85,85" fill="none" stroke="currentColor" stroke-width="3"/><polyline points="20,72 33,72 33,85" fill="none" stroke="currentColor" stroke-width="2"/></svg>

> ⚠️ الفخّ الشائع: الخلط بين متساوي الساقين ومتساوي الأضلاع؛ **متساوي الساقين** له ضلعان متساويان فقط، أمّا **متساوي الأضلاع** فأضلاعه الثلاثة متساوية.

## 🟦 الرباعيّات وخصائصها

**الرباعيّ** مضلّعٌ له 4 أضلاع و4 رؤوس و4 زوايا. أشهر أنواعه:

- **المربّع:** 4 أضلاع متساوية و4 زوايا قائمة.

<svg viewBox="0 0 100 100"><rect x="20" y="20" width="60" height="60" fill="none" stroke="currentColor" stroke-width="3"/><polyline points="20,32 32,32 32,20" fill="none" stroke="currentColor" stroke-width="2"/></svg>

- **المستطيل:** 4 زوايا قائمة، والأضلاع المتقابلة متساوية ومتوازية (طولٌ وعرض).

<svg viewBox="0 0 100 100"><rect x="12" y="32" width="76" height="36" fill="none" stroke="currentColor" stroke-width="3"/><polyline points="12,44 24,44 24,32" fill="none" stroke="currentColor" stroke-width="2"/></svg>

- **المعيّن:** 4 أضلاع متساوية، والأضلاع المتقابلة متوازية (لكن زواياه ليست قائمةً بالضرورة).

<svg viewBox="0 0 100 100"><polygon points="50,15 85,50 50,85 15,50" fill="none" stroke="currentColor" stroke-width="3"/></svg>

- **متوازي الأضلاع:** الأضلاع المتقابلة متوازية ومتساوية (لكن أضلاعه الأربعة غير متساوية بالضرورة وزواياه ليست قائمة).

<svg viewBox="0 0 100 100"><polygon points="30,30 90,30 70,70 10,70" fill="none" stroke="currentColor" stroke-width="3"/></svg>

| الخاصّية                  | المربّع | المستطيل | المعيّن | متوازي الأضلاع |
| ------------------------- | ------- | -------- | ------- | -------------- |
| كلّ الأضلاع متساوية       | نعم     | لا       | نعم     | لا             |
| الأضلاع المتقابلة متوازية | نعم     | نعم      | نعم     | نعم            |
| كلّ الزوايا قائمة         | نعم     | نعم      | لا      | لا             |

> 🗡️ المربّع حالةٌ خاصّة: هو **مستطيلٌ** (زواياه قائمة) و**معيّنٌ** (كلّ أضلاعه متساوية) في آنٍ واحد.

> ⚠️ الفخّ الشائع: اعتبار كلّ رباعيٍّ أضلاعه متساوية مربّعًا؛ المعيّن أيضًا كلّ أضلاعه متساوية لكنّ زواياه ليست قائمة. المربّع يشترط الأمرين معًا.

## ⭕ الدائرة

**الدائرة** خطٌّ منحنٍ مغلق، كلّ نقاطه على **نفس المسافة** من نقطةٍ ثابتة تُسمّى **المركز**.

- **المركز (O):** النقطة الثابتة في وسط الدائرة.
- **الشعاع:** قطعةٌ تصل المركز بأيّ نقطةٍ على الدائرة. كلّ الأشعّة متساوية.
- **القطر:** قطعةٌ تصل نقطتين على الدائرة وتمرّ بالمركز. القطر يساوي **شعاعين**:

$$القطر = 2 × الشعاع$$

<svg viewBox="0 0 100 100"><circle cx="50" cy="50" r="38" fill="none" stroke="currentColor" stroke-width="3"/><line x1="12" y1="50" x2="88" y2="50" stroke="currentColor" stroke-width="2"/><circle cx="50" cy="50" r="2.5" fill="currentColor"/></svg>

نرسم الدائرة بـ**الفرجار**: نثبّت إبرته في المركز ونفتحه بمقدار الشعاع ثمّ ندير القلم دورةً كاملة.

> ⚡ مثال محلول: دائرةٌ شعاعها 4 سم. قطرها = 2 × 4 = 8 سم.
>
> ومثالٌ عكسيّ: دائرةٌ قطرها 10 سم، فشعاعها = 10 ÷ 2 = 5 سم.

> ⚠️ الفخّ الشائع: الخلط بين الشعاع والقطر؛ تذكّر أنّ القطر يمرّ بالمركز ويساوي **ضعف** الشعاع.

> 🏆 لقد عبرت بوّابة الهندسة! صرت تميّز التوازي من التعامد، وأنواع الزوايا والمثلّثات والرباعيّات، وتعرف أجزاء الدائرة وعلاقة القطر بالشعاع. استعدّ للبوّابة الموالية!', '# 📜 ملخّص: الهندسة

- **التوازي (∥):** مستقيمان لا يتقاطعان أبدًا ويحفظان نفس المسافة بينهما؛ نتحقّق بالمسطرة والكوس.
- **التعامد (⊥):** مستقيمان يتقاطعان مكوّنَين زاويةً قائمة (90 درجة)؛ نتحقّق بالكوس ونضع علامة الزاوية القائمة.
- **أنواع الزوايا:** حادّة (أقلّ من 90)، قائمة (90)، منفرجة (بين 90 و 180)، مستقيمة (180 درجة).
- **أنواع المثلّثات:** قائم (فيه زاوية قائمة)، متساوي الساقين (ضلعان متساويان)، متساوي الأضلاع (الأضلاع الثلاثة متساوية)، أيّ مثلّث (أضلاعه مختلفة).
- **الرباعيّات:** المربّع (4 أضلاع متساوية + 4 زوايا قائمة)، المستطيل (4 زوايا قائمة + الأضلاع المتقابلة متساوية)، المعيّن (4 أضلاع متساوية بلا زوايا قائمة)، متوازي الأضلاع (الأضلاع المتقابلة متوازية ومتساوية).
- **المربّع** مستطيلٌ ومعيّنٌ معًا (زواياه قائمة وكلّ أضلاعه متساوية).
- **الدائرة:** المركز نقطةٌ ثابتة في الوسط؛ الشعاع يصل المركز بالدائرة؛ القطر يمرّ بالمركز ويساوي شعاعين: القطر = 2 × الشعاع.', 11)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('242785f0-beea-54f0-9857-d477e24852c0', 'math-5eme', 'التناظر المحوري', 'معنى التناظر المحوري ومحور التناظر، خصائص النقطة ونظيرها (تساوي البُعد عن المحور، والمحور عموديّ على القطعة الواصلة بينهما ويمرّ بمنتصفها)، الأشكال المتناظرة، عدد محاور تناظر الأشكال المألوفة، وإكمال شكلٍ بالتناظر', '# ⚔️ التناظر المحوري — مرآةٌ في الهندسة

> 💡 «إذا طويتَ ورقةً على رسمٍ فانطبق نصفاه أحدهما على الآخر، فقد عثرتَ على محور تناظره.»

الفراشة، ووجه الإنسان، وحرف A، وقلبٌ مرسوم… كلّها أشكالٌ **متناظرة**: نصفها صورةٌ معكوسة للنصف الآخر. في هذه البوّابة تتعلّم **التناظر المحوري**، ومحور التناظر، وكيف ترسم نظير نقطةٍ وتُكمل شكلًا بالتناظر.

## 🪞 ما هو التناظر المحوري؟

يكون لشكلٍ **تناظرٌ محوري** إذا وُجد خطٌّ مستقيم — يُسمّى **محور التناظر** — إذا طُوي الشكل عليه **انطبق نصفاه** تمامًا أحدهما على الآخر.

نقول إنّ النصف الأوّل **نظير** النصف الثاني بالنسبة لذلك المحور.

<svg viewBox="0 0 100 100"><line x1="50" y1="8" x2="50" y2="92" stroke="currentColor" stroke-width="1.5" stroke-dasharray="4 3"/><path d="M50 35 C40 18 18 28 30 48 C36 58 50 68 50 68" fill="none" stroke="currentColor" stroke-width="2"/><path d="M50 35 C60 18 82 28 70 48 C64 58 50 68 50 68" fill="none" stroke="currentColor" stroke-width="2"/></svg>

## 📏 خصائص النقطة ونظيرها

النقطة A ونظيرتها ''A بالنسبة لمحورٍ تحقّقان:

<svg viewBox="0 0 100 100"><line x1="50" y1="10" x2="50" y2="90" stroke="currentColor" stroke-width="1.5" stroke-dasharray="4 3"/><circle cx="22" cy="50" r="3" fill="currentColor"/><circle cx="78" cy="50" r="3" fill="currentColor"/><line x1="22" y1="50" x2="78" y2="50" stroke="currentColor" stroke-width="1"/><circle cx="50" cy="50" r="2" fill="currentColor"/><text x="14" y="46" font-size="11" fill="currentColor">A</text><text x="80" y="46" font-size="11" fill="currentColor">A''</text></svg>

- النقطتان على **بُعدٍ متساوٍ** من المحور.
- المحور **عموديّ** على القطعة [A''A] ويمرّ بـ**منتصفها**.
- إذا كانت نقطةٌ **على المحور** نفسه، فبُعدها عنه صفر، فنظيرها **هو نفسها**.

> 🧭 مثال: إذا بَعُدت A عن المحور 4 cm، فإنّ نظيرتها ''A تبعد 4 cm عن المحور من الجهة الأخرى، والمسافة بينهما = 4 + 4 = 8 cm.

## 🟦 محاور تناظر بعض الأشكال

| الشكل                  | عدد محاور التناظر |
| ---------------------- | ----------------- |
| المثلّث متساوي الساقين | 1                 |
| المثلّث متساوي الأضلاع | 3                 |
| المستطيل (غير المربّع) | 2                 |
| المربّع                | 4                 |
| الدائرة                | عددٌ لا نهائيّ    |

للمربّع 4 محاور تناظر: محوران يمرّان بمنتصفات الأضلاع، ومحوران قطريّان:

<svg viewBox="0 0 100 100"><rect x="25" y="25" width="50" height="50" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="50" y1="15" x2="50" y2="85" stroke="currentColor" stroke-width="1" stroke-dasharray="4 3"/><line x1="15" y1="50" x2="85" y2="50" stroke="currentColor" stroke-width="1" stroke-dasharray="4 3"/><line x1="18" y1="18" x2="82" y2="82" stroke="currentColor" stroke-width="1" stroke-dasharray="4 3"/><line x1="82" y1="18" x2="18" y2="82" stroke="currentColor" stroke-width="1" stroke-dasharray="4 3"/></svg>

أمّا المثلّث متساوي الساقين فله محورٌ واحد عموديّ على قاعدته يمرّ برأسه:

<svg viewBox="0 0 100 100"><polygon points="50,15 20,80 80,80" fill="none" stroke="currentColor" stroke-width="3"/><line x1="50" y1="8" x2="50" y2="90" stroke="currentColor" stroke-width="1.5" stroke-dasharray="4 3"/></svg>

## ✏️ إكمال شكلٍ بالتناظر

لإكمال شكلٍ بالنسبة لمحور: نأخذ كلّ نقطةٍ من النصف المرسوم، ونرسم نظيرها على **البُعد نفسه** من الجهة الأخرى للمحور، ثمّ نصل النقاط بالترتيب نفسه. فيكون الناتج **صورةً معكوسة** مطابقة للنصف الأوّل.

<svg viewBox="0 0 100 100"><line x1="50" y1="8" x2="50" y2="92" stroke="currentColor" stroke-width="1.5" stroke-dasharray="4 3"/><polyline points="50,25 30,40 35,65 50,75" fill="none" stroke="currentColor" stroke-width="2"/><polyline points="50,25 70,40 65,65 50,75" fill="none" stroke="currentColor" stroke-width="2" stroke-dasharray="3 2"/></svg>

> ⚠️ الفخّ الشائع: الظنّ أنّ كلّ قطرٍ في الشكل محورُ تناظر؛ ليس كذلك دائمًا — قطر المستطيل (غير المربّع) **ليس** محور تناظرٍ له، وكذلك لا محور تناظر لمتوازي الأضلاع العامّ.

> 🏆 مبروك! بإتمامك التناظر المحوري تكون قد أتقنتَ مرآة الهندسة، وصرتَ قادرًا على رسم النظير وإكمال أيّ شكلٍ متناظر.', '# 📜 ملخّص: التناظر المحوري

- **التناظر المحوري:** لشكلٍ تناظرٌ محوري إذا وُجد محورٌ إذا طُوي الشكل عليه انطبق نصفاه تمامًا.
- **محور التناظر:** خطّ الطيّ الذي يقسم الشكل إلى نصفين متطابقين، أحدهما نظير الآخر.
- **خصائص النقطة ونظيرها:** هما على بُعدٍ متساوٍ من المحور، والمحور عموديّ على القطعة الواصلة بينهما ويمرّ بمنتصفها؛ ونظير نقطةٍ على المحور هو نفسها.
- **المسافة بين النقطة ونظيرها:** تساوي ضعف بُعد النقطة عن المحور.
- **عدد محاور التناظر:** المثلّث متساوي الساقين 1، متساوي الأضلاع 3، المستطيل 2، المربّع 4، الدائرة عددٌ لا نهائيّ.
- **إكمال شكلٍ متناظر:** نرسم نظير كلّ نقطةٍ على البُعد نفسه من الجهة الأخرى للمحور ثمّ نصل النقاط.
- **الفخّ:** ليس كلّ قطرٍ محورَ تناظر (قطر المستطيل ليس محور تناظر)، ولا محور تناظر لمتوازي الأضلاع العامّ.', 12)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

