INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e551fe4-3ae5-5b21-9d60-cc6bbe9289cd', '2ce7cead-dbbf-5460-9c60-dbd619c7e1db', 'ما قيمة الرقم 9 حسب رتبته في العدد 391 200؟', '[{"id":"a","text":"90 000"},{"id":"b","text":"900 000"},{"id":"c","text":"9 000"},{"id":"d","text":"900"}]'::jsonb, 'a', 'نُقسّم العدد أصنافًا: 391 | 200. الرقم 9 في رتبة عشرات الآلاف، فقيمته حسب رتبته = 9 × 10 000 = 90 000.', 5)
