INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cae2d7e8-b279-5166-ab65-2eb9082796ff', '2a852c65-9bf8-5cbf-8a46-14530a4651c3', 'أنا عددٌ من ستّة أرقام: رقمُ مئات آلافي 4 ومجموع جميع أرقامي الأخرى يساوي صفرًا. من أكون؟', '[{"id":"a","text":"4"},{"id":"b","text":"40 000"},{"id":"c","text":"400 000"},{"id":"d","text":"4 000 000"}]'::jsonb, 'c', 'رقم مئات الآلاف 4 وبقيّة الأرقام أصفار (مجموعها صفر)، فالعدد من ستّة أرقام هو 4 ثمّ خمسة أصفار: 400 000.', 1)
