INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('53bf1c79-d13d-50ce-a42b-d19cdf9e13a6', '2a852c65-9bf8-5cbf-8a46-14530a4651c3', 'عددٌ إذا أضفنا إليه 1 صار 600 000. ما هو هذا العدد؟', '[{"id":"a","text":"600 001"},{"id":"b","text":"599 000"},{"id":"c","text":"60 000"},{"id":"d","text":"599 999"}]'::jsonb, 'd', 'العدد المطلوب هو سابق 600 000، أي 600 000 − 1 = 599 999. (التحقّق: 599 999 + 1 = 600 000.)', 2)
