INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6ba2256-be6b-5c26-bc80-35b9c1b2d857', '2a852c65-9bf8-5cbf-8a46-14530a4651c3', 'ما أكبر عددٍ من ستّة أرقام رقمُ مئات آلافه 3 ورقمُ آحاده 0؟', '[{"id":"a","text":"399 990"},{"id":"b","text":"399 900"},{"id":"c","text":"399 999"},{"id":"d","text":"390 000"}]'::jsonb, 'a', 'رقم مئات الآلاف مثبَّت (3) ورقم الآحاد مثبَّت (0)؛ لجعل العدد أكبر ما يمكن نختار 9 لكلّ الرتب بينهما، فنحصل على 399 990. أمّا 399 999 فرقمُ آحاده 9 لا 0.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
