  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd306db4-52fe-5133-bbe9-bed76185403c', '2a852c65-9bf8-5cbf-8a46-14530a4651c3', 'باستعمال الأرقام 9 و 0 و 4 و 1 و 7 و 0 (الصفر مرّتين) مرّةً واحدة لكلٍّ منها، ما أصغر عددٍ من ستّة أرقام يمكن تكوينه؟', '[{"id":"a","text":"100 479"},{"id":"b","text":"100 749"},{"id":"c","text":"104 790"},{"id":"d","text":"100 794"}]'::jsonb, 'a', 'لا يجوز أن يبدأ العدد بالصفر، فنضع 1 (أصغر رقمٍ غير الصفر) في مئات الآلاف، ثمّ الصفرين، ثمّ نرتّب الباقي تصاعديًّا 4 ثمّ 7 ثمّ 9: 100 479.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8dda4bcc-671a-5ec1-b523-0ad542399682', '2a852c65-9bf8-5cbf-8a46-14530a4651c3', 'ما الترتيب التنازليّ الصحيح للأعداد 808 080 و 880 008 و 800 808؟', '[{"id":"a","text":"808 080 > 880 008 > 800 808"},{"id":"b","text":"800 808 > 808 080 > 880 008"},{"id":"c","text":"880 008 > 808 080 > 800 808"},{"id":"d","text":"880 008 > 800 808 > 808 080"}]'::jsonb, 'c', 'رتبة مئات الآلاف نفسها (8)؛ نقارن عشرات الآلاف: 8 (في 880 008) الأكبر، ثمّ بين 808 080 و 800 808 نقارن الآلاف: 8 > 0. إذن تنازليًّا: 880 008 > 808 080 > 800 808.', 5)
