INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e24e346e-6a70-572f-9c2d-79d2962aa793', '2a852c65-9bf8-5cbf-8a46-14530a4651c3', 'عددٌ من سبعة أرقام: رقمُ ملايينه 2، ومجموع رقمَي ملايينه وآحاده يساوي 9، وبقيّة أرقامه أصفار. ما هو؟', '[{"id":"a","text":"2 000 009"},{"id":"b","text":"2 000 007"},{"id":"c","text":"2 000 002"},{"id":"d","text":"9 000 002"}]'::jsonb, 'b', 'رقم الملايين 2 وبقيّة الرتب أصفار عدا الآحاد. ومجموع الملايين والآحاد 9، فرقمُ الآحاد = 9 − 2 = 7. إذن العدد 2 000 007.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
