INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('23852d50-058c-508c-9c3b-e475af967269', '5540cfdc-0cb4-5777-8b33-a5544aa72822', 'ما الترتيب التصاعديّ الصحيح للأعداد 540 000 و 54 000 و 504 000؟', '[{"id":"a","text":"540 000 < 504 000 < 54 000"},{"id":"b","text":"54 000 < 504 000 < 540 000"},{"id":"c","text":"54 000 < 540 000 < 504 000"},{"id":"d","text":"504 000 < 54 000 < 540 000"}]'::jsonb, 'b', 'العدد 54 000 من خمسة أرقام فهو الأصغر. والباقيان من ستّة أرقام: نقارن 540 000 و 504 000 في رتبة عشرات الآلاف: 0 < 4، فـ 504 000 أصغر. إذن: 54 000 < 504 000 < 540 000.', 4)
