INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('10fab923-b487-5e10-bccc-ad66fdb07662', 'd684dc7e-cf1c-51a0-835f-58c211e5a361', 'في القسمة الإقليدية 38 ÷ 5، ما الخارج والباقي؟', '[{"id":"a","text":"الخارج 7 والباقي 3"},{"id":"b","text":"الخارج 6 والباقي 8"},{"id":"c","text":"الخارج 8 والباقي 2"},{"id":"d","text":"الخارج 7 والباقي 5"}]'::jsonb, 'a', 'أكبر مضاعفٍ لـ 5 لا يتجاوز 38 هو 35 = 5 × 7، فالخارج 7 والباقي 38 − 35 = 3. ونتحقّق: 5 × 7 + 3 = 38، والباقي 3 أصغر من 5 ✓.', 1)
