INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a522e1c5-69dc-5e64-8a89-5306eda1128f', 'd684dc7e-cf1c-51a0-835f-58c211e5a361', 'قسمةٌ إقليدية مقسومُ عليها 6 وخارجها 9 وباقيها 4. ما المقسوم؟', '[{"id":"a","text":"54"},{"id":"b","text":"58"},{"id":"c","text":"60"},{"id":"d","text":"13"}]'::jsonb, 'b', 'نستعمل العلاقة الأساسية: المقسوم = المقسوم عليه × الخارج + الباقي = 6 × 9 + 4 = 54 + 4 = 58. والباقي 4 أصغر من المقسوم عليه 6 ✓.', 3)
