INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ade913e1-d403-560e-bd49-31b1404c28be', '61eecc80-1ed0-579a-afcf-ae74b8d40128', 'في القسمة الإقليدية 137 ÷ 6، ما الخارج والباقي؟', '[{"id":"a","text":"الخارج 21 والباقي 11"},{"id":"b","text":"الخارج 22 والباقي 5"},{"id":"c","text":"الخارج 23 والباقي 1"},{"id":"d","text":"الخارج 22 والباقي 7"}]'::jsonb, 'b', 'أكبر مضاعفٍ لـ 6 لا يتجاوز 137 هو 132 = 6 × 22، فالخارج 22 والباقي 137 − 132 = 5، و 5 أصغر من 6 ✓. ونتحقّق 6 × 22 + 5 = 137.', 1)
