INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f6240ff-c485-5d52-aad4-3efe8df35636', 'b45f98f1-ec63-55b4-9b45-b4f9adad5c20', 'ما أكبر عددٍ من رقمين يعطي في قسمته الإقليدية على 6 باقيًا يساوي 4؟', '[{"id":"a","text":"98"},{"id":"b","text":"94"},{"id":"c","text":"96"},{"id":"d","text":"100"}]'::jsonb, 'b', 'نريد عددًا من رقمين على شكل 6 × خارج + 4. نجرّب أكبر خارجٍ ممكن: 6 × 15 + 4 = 94 (من رقمين). أمّا 6 × 16 + 4 = 100 فمن ثلاثة أرقام. ونتحقّق 94 ÷ 6 = 15 وباقٍ 4، و 4 < 6 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
