INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07e36f39-0aa0-5877-b0e9-f8fb516cb311', 'b45f98f1-ec63-55b4-9b45-b4f9adad5c20', 'بتمديد القسمة، ما القيمة العشريّة الدقيقة لـ 18 ÷ 8؟', '[{"id":"a","text":"2,2"},{"id":"b","text":"2,4"},{"id":"c","text":"2,25"},{"id":"d","text":"2,5"}]'::jsonb, 'c', '8 يدخل في 18 مرّتين (8 × 2 = 16) والباقي 2؛ نُنزل صفرًا فيصير 20: 8 × 2 = 16 والباقي 4؛ نُنزل صفرًا فيصير 40: 8 × 5 = 40 تمامًا. إذن 18 ÷ 8 = 2,25، ونتحقّق 8 × 2,25 = 18 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
