INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a0ed095-1dbc-5f34-9b96-45919b38ccf4', 'b030d87b-fe85-5893-96bf-5a7603e7345b', 'في القسمة الإقليدية 115 ÷ 9، ما الخارج والباقي؟', '[{"id":"a","text":"الخارج 11 والباقي 16"},{"id":"b","text":"الخارج 12 والباقي 7"},{"id":"c","text":"الخارج 13 والباقي 2"},{"id":"d","text":"الخارج 12 والباقي 9"}]'::jsonb, 'b', 'أكبر مضاعفٍ لـ 9 لا يتجاوز 115 هو 108 = 9 × 12، فالخارج 12 والباقي 115 − 108 = 7، و 7 أصغر من 9 ✓. ونتحقّق 9 × 12 + 7 = 115.', 1)
