INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b882e3a7-9a54-5c34-a200-cf51b46e2e56', 'b030d87b-fe85-5893-96bf-5a7603e7345b', 'ما ناتج 605 ÷ 100؟', '[{"id":"a","text":"6,05"},{"id":"b","text":"60,5"},{"id":"c","text":"0,605"},{"id":"d","text":"6,5"}]'::jsonb, 'a', 'للقسمة على 100 نُزحزح الفاصلة خانتين نحو اليسار، فيصير 605 هو 6,05. الجواب 60,5 يوافق القسمة على 10 فقط.', 3)
