INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('13b86a83-7357-5d5e-8758-b4fbc91f48b3', 'b030d87b-fe85-5893-96bf-5a7603e7345b', 'في حفلٍ 53 ضيفًا، وكلّ طاولةٍ تَسَع 6 ضيوف. كم طاولةً تلزم لجلوس الجميع؟', '[{"id":"a","text":"8 طاولات"},{"id":"b","text":"10 طاولات"},{"id":"c","text":"9 طاولات"},{"id":"d","text":"7 طاولات"}]'::jsonb, 'c', '53 ÷ 6 = 8 وباقٍ 5 (لأنّ 6 × 8 = 48 و 53 − 48 = 5). تمتلئ 8 طاولاتٍ ويبقى 5 ضيوفٍ يحتاجون طاولةً تاسعة، فالعدد اللازم 9 طاولات (نُدوّر إلى الأعلى).', 5)
